customCSS:
/* Bitcoin Laser — Laser Eyes Activated */
@import url('https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700&family=Inter:wght@300;400;500;600&family=Fira+Code&display=swap');

.cyber-glow {
  background:
    radial-gradient(ellipse 500px 300px at 50% 0%, rgba(247, 147, 26, 0.1), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(247, 147, 26, 0.15);
  background: rgba(22, 22, 22, 0.95);
  backdrop-filter: none;
}

.stat-card::before {
  background: linear-gradient(90deg, #f7931a, #ffd700);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(247, 147, 26, 0.4);
  box-shadow: 0 0 20px rgba(247, 147, 26, 0.15);
}

.stat-value {
  color: #f7931a;
  text-shadow: 0 0 12px rgba(247, 147, 26, 0.4);
}

.celebration-title {
  color: #f7931a !important;
  text-shadow: 0 0 30px rgba(247, 147, 26, 0.6);
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(247, 147, 26, 0.08);
  background: rgba(22, 22, 22, 0.9);
}

.miner-card:hover {
  border-color: rgba(247, 147, 26, 0.25);
}

.logo {
  color: #f7931a;
  text-shadow: 0 0 25px rgba(247, 147, 26, 0.5);
}
